package knowledge

import "github.com/silasdev78/silas-code-inspector/internal/domain"

func TactPatterns() []domain.Pattern {
	return []domain.Pattern{
		{ID: "TACT-001", Title: "Missing seqno check", Regex: `receive\s*\(\s*(?:msg\s*:\s*\w+|"[^"]*")\s*\)\s*\{`, Severity: domain.SeverityCritical, Description: "External messages must check seqno to prevent replay attacks.", Recommendation: "Add require(self.seqno == msg.seqno) inside receive()."},
		{ID: "TACT-002", Title: "Unchecked sender", Regex: `receive\s*\(\s*(?:msg\s*:\s*\w+|"[^"]*")\s*\)\s*\{`, Severity: domain.SeverityHigh, Description: "Missing sender verification allows anyone to call this function.", Recommendation: "Add require(msg.sender == owner)."},
		{ID: "TACT-003", Title: "Unprotected selfdestruct", Regex: `selfdestruct\s*\(`, Severity: domain.SeverityCritical, Description: "selfdestruct without sender check can be called by anyone.", Recommendation: "Wrap selfdestruct in a require with owner check."},
		{ID: "TACT-004", Title: "Integer overflow/underflow", Regex: `\b(?:Int|int)\s*\.\s*(?:\+|\-|\*)`, Severity: domain.SeverityHigh, Description: "Arithmetic operations may overflow without safe math checks.", Recommendation: "Use require(result >= a) for additions or import safe math."},
		{ID: "TACT-005", Title: "Hardcoded address", Regex: `"[EQ][a-zA-Z0-9_-]{47,}"`, Severity: domain.SeverityInfo, Description: "Hardcoded address found. Ensure it's intentional.", Recommendation: "Consider using a config constant."},
		{ID: "TACT-006", Title: "Unbounded loop", Regex: `\bwhile\s*\(`, Severity: domain.SeverityHigh, Description: "Loops without gas limits can cause out-of-gas errors.", Recommendation: "Add a max iteration guard."},
		{ID: "TACT-007", Title: "External call in loop", Regex: `\.\s*send\s*\(`, Severity: domain.SeverityMedium, Description: "Sending messages inside loops consumes unpredictable gas.", Recommendation: "Batch transfers or use a single message."},
		{ID: "TACT-008", Title: "Missing storage fee consideration", Regex: `storageReserve\s*\(`, Severity: domain.SeverityMedium, Description: "Contract may lack storage fee management.", Recommendation: "Add regular storage fee top-ups."},
		{ID: "TACT-009", Title: "Timeout not enforced", Regex: `receive\s*\(\s*(?:msg\s*:\s*\w+|"[^"]*")\s*\)\s*\{`, Severity: domain.SeverityLow, Description: "No timeout logic for time-sensitive operations.", Recommendation: "Add a deadline check with now()."},
		{ID: "TACT-010", Title: "Uninitialized variable", Regex: `\bvar\s+\w+\s*:\s*\w+;`, Severity: domain.SeverityLow, Description: "Variable declared without initial value may be nil.", Recommendation: "Initialize with a sensible default."},
		{ID: "TACT-011", Title: "Gas check missing", Regex: `receive\s*\(\s*(?:msg\s*:\s*\w+|"[^"]*")\s*\)\s*\{`, Severity: domain.SeverityMedium, Description: "No gas-usage limit set for receive function.", Recommendation: "Add require(gasConsumed < MAX_GAS)."},
		{ID: "TACT-012", Title: "Old compiler version", Regex: `^\s*\/\/\s*compiler\s*:`, Severity: domain.SeverityLow, Description: "Compiler version might be outdated, leading to bugs.", Recommendation: "Update to latest Tact compiler."},
		{ID: "TACT-013", Title: "Signature verification missing", Regex: `receive\s*\(\s*(?:msg\s*:\s*\w+|"[^"]*")\s*\)\s*\{`, Severity: domain.SeverityHigh, Description: "No signature verification for critical actions.", Recommendation: "Use checkDataSign or similar."},
		{ID: "TACT-014", Title: "Unchecked return value", Regex: `\.\s*send\s*\(`, Severity: domain.SeverityMedium, Description: "send() return flag ignored; message might fail silently.", Recommendation: "Check the boolean return of send()."},
		{ID: "TACT-015", Title: "Missing state isolation", Regex: `\bstate\b\s*\{`, Severity: domain.SeverityLow, Description: "State declaration without clear isolation comment.", Recommendation: "Document state invariants."},
		{ID: "TACT-016", Title: "Insecure random source", Regex: `\brandom\s*\(`, Severity: domain.SeverityHigh, Description: "Randomness may be predictable from block data.", Recommendation: "Use commitment schemes or off-chain randomness."},
		{ID: "TACT-017", Title: "Lack of access control modifier", Regex: `\bfun\s+\w+\s*\(`, Severity: domain.SeverityMedium, Description: "Functions without access modifiers may be public by default.", Recommendation: "Explicitly declare visibility."},
		{ID: "TACT-018", Title: "Exposed internal function", Regex: `\bpublic\s+fun\s+internal\w*`, Severity: domain.SeverityInfo, Description: "Naming suggests internal logic but marked public.", Recommendation: "Make private or clearly document."},
		{ID: "TACT-019", Title: "Unchecked msg value", Regex: `receive\s*\(\s*(?:msg\s*:\s*\w+|"[^"]*")\s*\)\s*\{`, Severity: domain.SeverityLow, Description: "No check on msg.value allows zero-value calls.", Recommendation: "Add require(msg.value > 0)."},
		{ID: "TACT-020", Title: "Missing code upgrade path", Regex: `\bcode\s*:`, Severity: domain.SeverityInfo, Description: "No mechanism for code upgrade, contract is immutable.", Recommendation: "Consider a proxy pattern or upgradeable state."},
		{ID: "TACT-021", Title: "Unhandled bounced messages", Regex: `receive\s*\(\s*bounced\b`, Severity: domain.SeverityCritical, Description: "Bounced messages not handled; can cause asset lockup.", Recommendation: "Always add a receive(bounced) handler and recovery logic."},
		{ID: "TACT-022", Title: "Possible message race condition", Regex: `\.send\([^)]*\)\s*\{?`, Severity: domain.SeverityHigh, Description: "State changes after send() may cause inconsistency due to async messaging. Manual review required.", Recommendation: "Use carry-value pattern instead of relying on state."},
		{ID: "TACT-023", Title: "Insufficient balance check before transfer", Regex: `balances\[\w+\]\s*-\s*\w+`, Severity: domain.SeverityCritical, Description: "Balance subtraction without prior require(balance >= amount) may cause underflow or theft.", Recommendation: "Add require(balance >= amount) before updating."},
		{ID: "TACT-024", Title: "Division before multiplication", Regex: `\w+\s*/\s*\w+\s*\*`, Severity: domain.SeverityHigh, Description: "Incorrect order of operations leads to precision loss in financial calculations.", Recommendation: "Multiply first, then divide."},
		{ID: "TACT-025", Title: "Block dependency for randomness", Regex: `\b(?:now|block_lt)\s*\(\s*\)`, Severity: domain.SeverityHigh, Description: "Randomness derived from block time or logical time is predictable.", Recommendation: "Use nativeRandom with commit-reveal or off-chain oracle."},
		{ID: "TACT-026", Title: "Insecure proxy pattern", Regex: `\bupgrade\b|self\.code\s*=`, Severity: domain.SeverityCritical, Description: "Proxy pattern detected; ensure storage layout compatibility to avoid collisions.", Recommendation: "Follow unstructured storage proxy pattern and test thoroughly."},
		{ID: "TACT-027", Title: "Use of any type", Regex: `\bany\b`, Severity: domain.SeverityMedium, Description: "Loss of type safety can lead to unexpected behavior.", Recommendation: "Specify concrete types."},
		{ID: "TACT-028", Title: "Large message size risk", Regex: `\.send\s*\(\s*\w+\s*,\s*\w+\s*,\s*\d{3,}\s*\)`, Severity: domain.SeverityMedium, Description: "Message size exceeding ~4KB may be rejected by the network.", Recommendation: "Chunk large data or compress."},
		{ID: "TACT-029", Title: "Missing jetton wallet code validation", Regex: `transfer_notification`, Severity: domain.SeverityCritical, Description: "Jetton transfer notification without verifying sender wallet code can be spoofed.", Recommendation: "Check that the sender wallet code matches the expected hash."},
		{ID: "TACT-030", Title: "Unsafe serialization (Int vs uint)", Regex: `\bInt\b\s*:\s*(?:uint|uint256)`, Severity: domain.SeverityHigh, Description: "Mismatch between Tact Int and standard uint256 may cause encoding errors.", Recommendation: "Use the correct integer type as per TEP-74."},
		{ID: "TACT-031", Title: "Missing gas pre-check", Regex: `receive\s*\(\s*(?:msg\s*:\s*\w+|"[^"]*")\s*\)\s*\{`, Severity: domain.SeverityCritical, Description: "Incoming message without gas check may lead to partial execution and inconsistent state.", Recommendation: "Add require(context().value > computeFee(...)) and forward remaining gas."},
		{ID: "TACT-032", Title: "Reliance on state across async messages", Regex: `\.send\([^)]*\)\s*\{`, Severity: domain.SeverityCritical, Description: "Data needed by subsequent messages should be carried in the message body, not stored in state.", Recommendation: "Use carry-value pattern: include all necessary data in the message."},
		{ID: "TACT-033", Title: "Address zero / optional mismatch", Regex: `Address\?`, Severity: domain.SeverityHigh, Description: "Mismatch between Tact non-zero Address and Jetton/NFT standards that allow zero.", Recommendation: "Check address != zero before using."},
		{ID: "TACT-034", Title: "Storage rent not considered", Regex: `storageReserve`, Severity: domain.SeverityHigh, Description: "Contract with low balance may be deleted by network due to storage rent.", Recommendation: "Regularly top-up storage reserve or maintain sufficient balance."},
		{ID: "TACT-035", Title: "Signature without domain/seqno", Regex: `checkSign\s*\([^,]*,\s*[^,]*\)`, Severity: domain.SeverityCritical, Description: "Signature verification missing seqno or domain can lead to replay across contracts.", Recommendation: "Include contract address and seqno in signed message."},
		{ID: "TACT-036", Title: "Mutable message parameters", Regex: `msg\.body\s*=|msg\.data\s*=`, Severity: domain.SeverityMedium, Description: "Modifying incoming message fields is discouraged and may lead to unexpected behavior.", Recommendation: "Use a local copy of message parameters."},
		{ID: "TACT-037", Title: "Unchecked external call result", Regex: `let\s+\w+\s*=\s*send\s*\(`, Severity: domain.SeverityHigh, Description: "send() return value not checked; failure may go unnoticed.", Recommendation: "Use require(send(...), \"send failed\")."},
		{ID: "TACT-038", Title: "Trait override without virtual", Regex: `override\s+fun\b(?!.*virtual)`, Severity: domain.SeverityMedium, Description: "Override function without virtual may cause initialization or diamond problems.", Recommendation: "Declare parent functions as virtual."},
		{ID: "TACT-039", Title: "Excessive storage without cleanup", Regex: `map\s*<\s*\w+\s*,\s*\w+\s*>\s*;`, Severity: domain.SeverityMedium, Description: "Maps can grow indefinitely, increasing storage fees.", Recommendation: "Add delete/cleanup logic for unused entries."},
		{ID: "TACT-040", Title: "Missing invariant check", Regex: `\bstate\b\s*\{`, Severity: domain.SeverityHigh, Description: "No post-condition validation after state modification.", Recommendation: "Add require() statements to enforce invariants."},
		{ID: "TACT-041", Title: "Deprecated compiler feature", Regex: `^\s*\/\/\s*compiler\s*:\s*0\.`, Severity: domain.SeverityLow, Description: "Very old compiler version or deprecated syntax.", Recommendation: "Upgrade to latest Tact compiler."},
		{ID: "TACT-042", Title: "Raw assembler usage", Regex: `\basm\s*\(|\bnative\s+\w+\s*\(`, Severity: domain.SeverityHigh, Description: "Inline assembly can break safety guarantees.", Recommendation: "Avoid or audit carefully."},
		{ID: "TACT-043", Title: "Fake jetton / NFT spoofing", Regex: `jetton_wallet_code\b`, Severity: domain.SeverityCritical, Description: "Jetton wallet code not verified allows spoofed tokens.", Recommendation: "Check that the wallet code hash equals the expected one."},
		{ID: "TACT-044", Title: "Sensitive data on-chain", Regex: `"(?:secret|password|private_key|mnemonic)"`, Severity: domain.SeverityHigh, Description: "Hardcoded sensitive data is publicly visible on blockchain.", Recommendation: "Never store secrets on-chain; use off-chain or zk proofs."},
		{ID: "TACT-045", Title: "Unbounded dictionary depth", Regex: `dict\s*\.\s*set\s*\(`, Severity: domain.SeverityHigh, Description: "Deep cell structures can cause gas explosions.", Recommendation: "Limit recursion or use simpler data structures."},
	}
}
